// Builds public-facing /connections/index.html from /tmp/rosetta/<key>.json
// (generated by the rosetta-connections workflow). Run: node tools/gen-connections.mjs
import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';

const SRC = '/tmp/rosetta';
const KEYS = ['variables','collections','map','filter','functions','loops','conditionals','strings','aggregation','joins','async','nullish'];

const LANG_COLOR = {
  JavaScript: '#eab308', Python: '#4b8bbe', SQL: '#3b82f6', R: '#276dc3', Pandas: '#e70488',
};

const esc = s => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const concepts = [];
for (const key of KEYS) {
  const p = `${SRC}/${key}.json`;
  if (!existsSync(p)) { console.warn('missing', p); continue; }
  try { concepts.push(JSON.parse(readFileSync(p, 'utf8'))); }
  catch (e) { console.warn('bad JSON', key, e.message); }
}
if (!concepts.length) { console.error('No concept data found in ' + SRC); process.exit(1); }

const toc = concepts.map(c => `<a href="#${c.key}">${esc(c.title)}</a>`).join('\n      ');

const sections = concepts.map(c => {
  const cols = (c.rows || []).map(r => {
    const color = LANG_COLOR[r.lang] || '#888';
    return `        <div class="conn-col">
          <div class="conn-lang" style="color:${color}"><span class="conn-dot" style="background:${color}"></span>${esc(r.lang)}</div>
          <pre class="conn-code"><code>${esc(r.code)}</code></pre>
        </div>`;
  }).join('\n');
  const insight = c.insight ? `      <p class="conn-insight"><span>Connection</span> ${esc(c.insight)}</p>` : '';
  return `    <section class="conn-concept" id="${c.key}">
      <h2>${esc(c.title)}</h2>
      <p class="conn-blurb">${esc(c.blurb || '')}</p>
      <div class="conn-grid">
${cols}
      </div>
${insight}
    </section>`;
}).join('\n\n');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Connections — Dev Lab</title>
  <meta name="description" content="The same idea in every language. Variables, maps, filters, functions, grouping, joins, and more — shown side by side across JavaScript, Python, SQL, R, and Pandas.">
  <link rel="icon" type="image/svg+xml" href="/favicon.svg">
  <link rel="stylesheet" href="/assets/base.css">
  <link rel="stylesheet" href="/assets/shell.css">
  <style>
    .conn-wrap { max-width: 1280px; margin: 0 auto; padding: 3rem 2rem 5rem; }
    .conn-hero h1 { font-family: var(--serif); font-size: clamp(1.8rem, 4vw, 2.6rem); font-weight: 400; line-height: 1.12; letter-spacing: -0.01em; margin-bottom: 0.6rem; }
    .conn-hero p { font-size: 1rem; line-height: 1.6; color: var(--text-dim); max-width: 640px; }
    .conn-toc { display: flex; flex-wrap: wrap; gap: 0.5rem; margin: 1.75rem 0 1rem; }
    .conn-toc a { font-family: var(--mono); font-size: 0.7rem; letter-spacing: 0.03em; padding: 0.35rem 0.7rem; border: 1px solid var(--border); border-radius: 6px; color: var(--text-dim); text-decoration: none; transition: all 0.18s; }
    .conn-toc a:hover { border-color: var(--text-dim); color: var(--text); background: var(--surface); }
    .conn-concept { padding-top: 3rem; border-top: 1px solid var(--border); margin-top: 2.5rem; scroll-margin-top: 80px; }
    .conn-concept:first-of-type { border-top: none; margin-top: 1.5rem; }
    .conn-concept h2 { font-family: var(--serif); font-size: 1.6rem; font-weight: 400; margin-bottom: 0.35rem; }
    .conn-blurb { font-size: 0.92rem; color: var(--text-dim); line-height: 1.6; margin-bottom: 1.5rem; max-width: 720px; }
    .conn-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 1rem; }
    .conn-col { border: 1px solid var(--border); border-radius: 10px; overflow: hidden; background: var(--surface); }
    .conn-lang { display: flex; align-items: center; gap: 0.45rem; font-family: var(--mono); font-size: 0.68rem; font-weight: 600; letter-spacing: 0.06em; text-transform: uppercase; padding: 0.7rem 1rem; border-bottom: 1px solid var(--border); }
    .conn-dot { width: 7px; height: 7px; border-radius: 50%; display: inline-block; }
    .conn-code { margin: 0; padding: 1rem; font-family: var(--mono); font-size: 0.78rem; line-height: 1.65; color: var(--text); overflow-x: auto; background: var(--bg); }
    .conn-code code { font-family: inherit; white-space: pre; }
    .conn-insight { margin-top: 1.25rem; font-size: 0.88rem; line-height: 1.6; color: var(--text-dim); border-left: 3px solid var(--accent-d3, #f97316); padding: 0.6rem 0 0.6rem 1rem; }
    .conn-insight span { font-family: var(--mono); font-size: 0.6rem; letter-spacing: 0.08em; text-transform: uppercase; color: var(--text-muted); display: block; margin-bottom: 0.2rem; }
    @media (max-width: 768px) { .conn-wrap { padding: 2rem 1.5rem 3rem; } .conn-grid { grid-template-columns: 1fr; } }
  </style>
</head>
<body>

  <header>
    <div class="header-inner">
      <a href="/" class="logo">&larr; <span class="accent">Dev Lab</span></a>
      <div class="header-right">
        <button class="theme-toggle" aria-label="Toggle theme">
          <svg class="icon-moon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>
          <svg class="icon-sun" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/></svg>
        </button>
      </div>
    </div>
  </header>

  <div class="conn-wrap">
    <div class="conn-hero">
      <h1>The same idea, in every language.</h1>
      <p>The fastest way to learn a new language is to see a concept you already know, written the other way. Here is the same small task across JavaScript, Python, SQL, R, and Pandas.</p>
      <nav class="conn-toc">
      ${toc}
      </nav>
    </div>

${sections}
  </div>

  <script>
    const toggle = document.querySelector('.theme-toggle');
    const saved = localStorage.getItem('theme');
    if (saved) document.documentElement.setAttribute('data-theme', saved);
    else if (window.matchMedia('(prefers-color-scheme: light)').matches) document.documentElement.setAttribute('data-theme', 'light');
    toggle.addEventListener('click', () => {
      const next = document.documentElement.getAttribute('data-theme') === 'light' ? 'dark' : 'light';
      document.documentElement.setAttribute('data-theme', next);
      localStorage.setItem('theme', next);
    });
  </script>
</body>
</html>
`;

mkdirSync('connections', { recursive: true });
writeFileSync('connections/index.html', html);
console.log(`Wrote connections/index.html — ${concepts.length} concepts, ${concepts.reduce((n,c)=>n+(c.rows?.length||0),0)} snippets`);
